let running = false; let timer = null; let count = 0;
const sdk = window.CueStack;

function toggleSimulation() {
  running = !running;
  const btn = document.getElementById('toggleBtn');
  const status = document.getElementById('status');
  if (running) {
    btn.textContent = 'Stop Simulation';
    btn.className = 'running';
    status.textContent = 'Running';
    status.style.background = '#f0fde8';
    status.style.color = '#15803d';
    startSending();
  } else {
    btn.textContent = 'Start Simulation';
    btn.className = '';
    status.textContent = 'Stopped';
    status.style.background = '#fef2f2';
    status.style.color = '#dc2626';
    clearInterval(timer);
  }
}

function startSending() {
  const rate = parseInt(document.getElementById('rate').value);
  clearInterval(timer);
  timer = setInterval(sendSample, rate);
}

function sendSample() {
  const channel = document.getElementById('channel').value;
  const meanT = parseFloat(document.getElementById('meanTemp').value);
  const meanH = parseFloat(document.getElementById('meanHumid').value);
  const noise = parseFloat(document.getElementById('noise').value);
  const freq = parseFloat(document.getElementById('freq').value);
  const t = count * (parseInt(document.getElementById('rate').value) / 1000);
  const temp = meanT + noise * (Math.random() - 0.5) * 2 + Math.sin(2 * Math.PI * freq * t);
  const humid = meanH + noise * (Math.random() - 0.5) * 2 + Math.cos(2 * Math.PI * freq * t) * 0.5;
  const payload = { temperature: +temp.toFixed(2), humidity: +humid.toFixed(2), t: t };
  sdk.publish(channel, payload);
  count++;
  document.getElementById('counter').textContent = count + ' samples sent';
  const log = document.getElementById('log');
  log.innerHTML = '<div>[' + new Date().toLocaleTimeString() + '] ' + channel + ': T=' + payload.temperature + '°C H=' + payload.humidity + '%</div>' + log.innerHTML;
  if (log.children.length > 50) log.lastChild.remove();
}

// Update slider labels
['meanTemp','meanHumid','noise','freq'].forEach(function(id) {
  const el = document.getElementById(id);
  const val = document.getElementById(id + 'Val');
  el.oninput = function() {
    const suffix = id === 'meanTemp' ? '°C' : id === 'meanHumid' ? '%' : id === 'freq' ? ' Hz' : '';
    val.textContent = el.value + suffix;
  };
});
